// ─────────────────────────────────────────────────────────────
// HELPERS
// ─────────────────────────────────────────────────────────────
const rnd    = (a, b) => Math.random() * (b - a) + a;
const rndInt = (a, b) => Math.floor(rnd(a, b + 1));
const pick   = (arr)  => arr[Math.floor(Math.random() * arr.length)];
const r2     = (n)    => Math.round(n * 100) / 100;

// slug: "iPhone 14" → "iphone-14"
function toSlug(title) {
  return title.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');
}

// SKU: category + title slug + id
function makeSKU(category, title, id) {
  const cat   = category.toUpperCase().slice(0, 3);
  const parts = title.toUpperCase().split(' ').slice(0, 2).map(w => w.slice(0, 3)).join('-');
  return `${cat}-${parts}-${String(id).padStart(3, '0')}`;
}

function makeBarcode() {
  return String(rndInt(1000000000000, 9999999999999));
}

// ─────────────────────────────────────────────────────────────
// IMAGE URL — key fix
// Groceries → real cdn.dummyjson.com paths (same as your sample)
// Others    → picsum.photos/seed/<slug> — ALWAYS returns a real photo
// ─────────────────────────────────────────────────────────────
function makeImages(product, id) {
  if (product.category === 'groceries' && product.groSlug) {
    const base = `https://cdn.dummyjson.com/product-images/groceries/${product.groSlug}`;
    return {
      images:    [`${base}/1.webp`],
      thumbnail: `${base}/thumbnail.webp`,
    };
  }

  // picsum.photos — seed = title slug → always same image for same product
  const slug      = toSlug(product.title);
  const imgUrl    = `https://picsum.photos/seed/${slug}/640/480`;
  const thumbUrl  = `https://picsum.photos/seed/${slug}-thumb/200/200`;
  return {
    images:    [imgUrl],
    thumbnail: thumbUrl,
  };
}

// ─────────────────────────────────────────────────────────────
// REVIEWS — exactly like your sample structure
// ─────────────────────────────────────────────────────────────
function makeReviews() {
  const count = rndInt(2, 5);
  const used  = new Set();

  return Array.from({ length: count }, () => {
    let reviewer;
    // avoid duplicate reviewer in same product
    do { reviewer = pick(REVIEWERS); } while (used.has(reviewer.email) && used.size < REVIEWERS.length);
    used.add(reviewer.email);

    const daysAgo = rndInt(0, 400);
    const date    = new Date(Date.now() - daysAgo * 86400000).toISOString();

    return {
      rating:        rndInt(1, 5),
      comment:       pick(COMMENTS),
      date,
      reviewerName:  reviewer.name,
      reviewerEmail: reviewer.email,
    };
  });
}

// ─────────────────────────────────────────────────────────────
// BUILD ONE PRODUCT — exact same shape as your sample
// ─────────────────────────────────────────────────────────────
function buildProduct(id, template) {
  const stock  = rndInt(0, 120);
  const { images, thumbnail } = makeImages(template, id);
  const now    = new Date().toISOString();

  return {
    id,
    title:               template.title,
    description:         `${template.title} — top-quality product in the ${template.category} category, trusted by thousands of customers worldwide.`,
    category:            template.category,
    price:               r2(template.price),
    discountPercentage:  r2(rnd(0.1, 20)),
    rating:              r2(rnd(1.5, 5.0)),
    stock,
    tags:                template.tags,
    sku:                 makeSKU(template.category, template.title, id),
    weight:              rndInt(1, 15),
    dimensions: {
      width:  r2(rnd(5, 30)),
      height: r2(rnd(5, 40)),
      depth:  r2(rnd(5, 30)),
    },
    warrantyInformation:  pick(WARRANTY),
    shippingInformation:  pick(SHIPPING),
    availabilityStatus:   stock === 0 ? 'Out of Stock' : pick(AVAILABILITY),
    reviews:              makeReviews(),       // ← real reviewer names + emails
    returnPolicy:         pick(RETURN_POLICY),
    minimumOrderQuantity: rndInt(1, 50),
    meta: {
      createdAt: now,
      updatedAt: now,
      barcode:   makeBarcode(),
      qrCode:    'https://cdn.dummyjson.com/public/qr-code.png',
    },
    images,                                    // ← real working URLs
    thumbnail,                                 // ← real working URL
  };
}

// ─────────────────────────────────────────────────────────────
// GENERATE 1000 PRODUCTS — id starts at 31
// ─────────────────────────────────────────────────────────────
const products = [];
let   id       = 31;

while (products.length < 1000) {
  for (const template of PRODUCT_POOL) {
    if (products.length >= 1000) break;
    products.push(buildProduct(id++, template));
  }
}

